import{_ as e,o as t,c as r,ak as o}from"./chunks/framework.D2SKCb-o.js";const c=JSON.parse('{"title":"关于","description":"","frontmatter":{},"headers":[],"relativePath":"about.md","filePath":"about.md"}'),i={name:"about.md"};function h(l,a,n,s,d,b){return t(),r("div",null,[...a[0]||(a[0]=[o('<h1 id="关于" tabindex="-1">关于 <a class="header-anchor" href="#关于" aria-label="Permalink to “关于”">​</a></h1><h2 id="mzkbot的诞生" tabindex="-1">mzkbot的诞生 <a class="header-anchor" href="#mzkbot的诞生" aria-label="Permalink to “mzkbot的诞生”">​</a></h2><p>BOT主从去年12月开始休学...自己的家长在外地工作，无论是现实的朋友还是网上交的朋友也去上学了，自己呆在家里好无聊...于是在这种情况下，mzkbot诞生了</p><p>因为mzk是我最喜欢的角色，所以我把这个机器人取名为“mzkbot”。原本mzkbot只是我的一个&quot;聊天搭子&quot;，直到bot进入了更多的群聊，bot就被很多人认识了（）</p><p>从12月到今天，mzkbot多了许许多多的功能，例如让mzk“说话”，PJSK查询，猜歌等，在此感谢每一个使用BOT的人的支持！也十分感谢Astrbot插件社区的开发者们</p><p>最后我也不知道应该写什么了..那就以后再补吧..总之BOT会一直运营下去的！我也会不断增加更多好玩的功能！</p><h2 id="使用到的ai模型" tabindex="-1">使用到的AI模型 <a class="header-anchor" href="#使用到的ai模型" aria-label="Permalink to “使用到的AI模型”">​</a></h2><h3 id="文本模型" tabindex="-1">文本模型 <a class="header-anchor" href="#文本模型" aria-label="Permalink to “文本模型”">​</a></h3><p>Qwen3.5系列,Qwen3系列,Deepseek-V3.2</p><h3 id="多模态模型" tabindex="-1">多模态模型 <a class="header-anchor" href="#多模态模型" aria-label="Permalink to “多模态模型”">​</a></h3><p>GLM-4.6V-Flash</p><h3 id="tts模型" tabindex="-1">TTS模型 <a class="header-anchor" href="#tts模型" aria-label="Permalink to “TTS模型”">​</a></h3><p>GPT-Sovits</p><h3 id="嵌入模型" tabindex="-1">嵌入模型 <a class="header-anchor" href="#嵌入模型" aria-label="Permalink to “嵌入模型”">​</a></h3><p>bge-large-zh-v1.5</p><h3 id="重排序模型" tabindex="-1">重排序模型 <a class="header-anchor" href="#重排序模型" aria-label="Permalink to “重排序模型”">​</a></h3><p>bge-reranker-v2-m3</p>',17)])])}const m=e(i,[["render",h]]);export{c as __pageData,m as default};
